1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Edge case: empty quote =====
6	  it("quote with empty item list returns premium 5 G (only processing fee)", () => {
7	    const result = quote({ customer: { yearsInsured: 0, previousContracts: 0 }, items: [] });
8	    expect(result.premium).toBe(5);
9	  });
10	
11	  // ===== Base premiums per item type =====
12	  it("quote for a single plain sword (newcomer, first insurance) returns premium 115 G (100 base + 10 first + 5 fee)", () => {
13	    const result = quote({
14	      customer: { yearsInsured: 0, previousContracts: 0 },
15	      items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
16	    });
17	    expect(result.premium).toBe(115);
18	  });
19	  it.todo("quote for a single plain amulet (newcomer, first insurance) returns premium 71 G (60 base + 6 first + 5 fee)");
20	  it.todo("quote for a single plain staff (newcomer, first insurance) returns premium 93 G (80 base + 8 first + 5 fee)");
21	  it.todo("quote for a single plain potion (newcomer, first insurance) returns premium 49 G (40 base + 4 first + 5 fee)");
22	  it.todo("quote for a single component (newcomer, first insurance) returns premium 33 G (25 base + 2.5 first → 27.5 + 5 fee = 32.5 → round up to 33 G)");
23	
24	  // ===== Block-of-3 alike components (base premium examples) =====
25	  it.todo("quote base premium for 2 runes is 50 G (no block)");
26	  it.todo("quote base premium for 3 runes is 60 G (block applies)");
27	  it.todo("quote base premium for 4 runes is 100 G (no block — block requires exactly 3)");
28	  it.todo("quote base premium for 7 runes is 175 G (no block: 7×25)");
29	
30	  // ===== Alike components clarification =====
31	  it.todo("quote base premium for 2 runes + 1 moonstone is 75 G (no block: different types)");
32	  it.todo("quote base premium for 3 runes + 3 moonstones is 120 G (two separate blocks)");
33	
34	  // ===== Item-specific modifiers in isolation =====
35	  it.todo("cursed sword item modifier adds 50% surcharge to that item's base (100 G → 150 G item subtotal)");
36	  it.todo("high-enchantment sword (enchantment 5) adds 30% surcharge to that item's base");
37	  it.todo("sword with enchantment 4 does NOT get high-enchantment surcharge");
38	  it.todo("cursed AND high-enchantment sword (enchantment 5) gets both surcharges");
39	
40	  // ===== Policy-wide modifiers in isolation =====
41	  it.todo("loyalty discount applies for customer with exactly 2 years (20% off policy base)");
42	  it.todo("loyalty discount does NOT apply for customer with 1 year");
43	  it.todo("first insurance surcharge adds 10% per item (each item in the quote is treated as first insurance)");
44	  it.todo("follow-up contract discount (-15%) applies to second quote in scenario");
45	
46	  // ===== Modifier scope (multi-item policy) =====
47	  it.todo("policy with cursed sword (100 G) + plain amulet (60 G) has policy base 160 G; curse adds 50 G (50% of sword only) → 210 G before policy modifiers and fee");
48	
49	  // ===== Integration: Newcomer with a cursed sword =====
50	  it.todo("newcomer (0 years) with cursed sword (steel, enchantment 3) gets premium 165 G (100 base + 50 curse + 10 first = 160 + 5 fee)");
51	
52	  // ===== Integration: Long-standing customer's second contract =====
53	  it.todo("3-year customer's second quote of cursed sword (steel, enchantment 7) gets premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first − 15 follow-up = 155 + 5 fee)");
54	
55	  // ===== Rounding rules =====
56	  it.todo("premium calculation yielding 197.5 G is rounded UP to 198 G (in MHPCO's favor)");
57	  it.todo("intermediate amounts are kept as fractions; only the final premium is rounded");
58	
59	  // ===== Claim: standard reimbursement =====
60	  it.todo("claim on regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 − 100 deductible)");
61	  it.todo("claim on a rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100 deductible; no special clause for components)");
62	
63	  // ===== Claim: enchantment threshold and dragon material =====
64	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins: 500 − 100)");
65	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement: 800 − 100)");
66	  it.todo("claim on steel sword, enchantment 9, damage 1000 G → payout 400 G (50% rule: 500 − 100)");
67	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench applies: 500 − 100)");
68	
69	  // ===== Claim: deductible per damage event =====
70	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → total payout 600 G (100 G deductible per damaged item: 400 + 200)");
71	
72	  // ===== Claim: multiple items of same type =====
73	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
74	  it.todo("dragon attack damages both of two insured swords → each damage entry gets its own deductible");
75	  it.todo("claim references more swords damaged than insured (2 sword damages, 1 sword insured) → error / rejection");
76	
77	  // ===== Claim: cap and insurance sum =====
78	  it.todo("policy with sword + amulet has insurance sum 1600 G and cap 3200 G");
79	  it.todo("policy with cursed sword has cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
80	  it.todo("policy with sword + 3 runes (block) has insurance sum 1750 G (block discount affects premium only, not insurance sum)");
81	
82	  // ===== Claim: cap exhaustion across successive claims =====
83	  it.todo("sword insured (cap 2000 G), first claim of 1500 G → payout 1400 G, remainingCap 600 G");
84	  it.todo("after first claim used 1400 G, second claim of 1500 G → payout 600 G (reduced to remaining cap), remainingCap 0 G");
85	
86	  // ===== Claim: payout rounding =====
87	  it.todo("payout calculation yielding 350.5 G is rounded DOWN to 350 G (in MHPCO's favor)");
88	
89	  // ===== Edge cases / errors =====
90	  it.todo("quote with unknown item type (e.g. broomstick) → error");
91	  it.todo("claim references damage to item not in policy (e.g. amulet damaged when only sword insured) → error");
92	  it.todo("claim references damage to unknown item type → error");
93	  it.todo("claim with negative damage amount → error");
94	
95	  // ===== CLI =====
96	  it.todo("CLI reads JSON scenario from stdin and writes JSON results to stdout (schema-example scenario)");
97	  it.todo("CLI exits with non-zero status on unknown item type in quote; writes error to stderr; no results on stdout");
98	  it.todo("CLI exits with non-zero status when claim references item not in policy; writes error to stderr");
99	  it.todo("CLI exits with non-zero status when claim contains negative damage amount; writes error to stderr");
100	  it.todo("CLI exits with non-zero status when claim has more damages of a type than policy covers");
101	});
